INSERT INTO public.questions (id, exam_id, paper_id, subject_id, chapter_id, question_type, question_text, options, correct_answer, correct_answer_json, auto_gradable, source, is_active, version, source_meta, explanation)
VALUES
  ('disabled-57f41407-moex-00636', 'disabled-57f41407', 'disabled-57f41407-moex-110-01c5eaab', 'sub-disabled-57f41407-04', NULL, 'single_choice', '「我不和你談論詩藝╱不和你談論那些糾纏不清的隱喻╱請離開書房╱ 我帶你去廣袤的田野走走╱去看看遍處的幼苗╱如何沉默地奮力生長」 下列何者最接近本詩的意思？', '["空言藝術美感，不如親身去體驗鄉土", "幼苗在無人關注的所在，仍奮力生長", "在書房閉門討論詩藝，有助提升造詣", "唯有寫作詩歌，才能頌讚土地的美好"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:38+00:00", "source_pdf_sha1": "9e93f40d41a4", "answer_pdf_sha1": "6bfdd34d238a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "505", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 35, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00637', 'disabled-57f41407', 'disabled-57f41407-moex-110-01c5eaab', 'sub-disabled-57f41407-04', NULL, 'single_choice', '「當我驚醒／當年輕的夢被午夜驚醒／被及胸的風／與花與雪與月／驚 醒／白髮，我聽到你一根／又一根裂膚而出的聲音」下列敘述，最符合詩 意的是：', '["為青春已逝而喟嘆", "以淡定心情看待歲月", "奉勸世人要及時努力", "後悔年輕時沉溺於風花雪月"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:38+00:00", "source_pdf_sha1": "9e93f40d41a4", "answer_pdf_sha1": "6bfdd34d238a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "505", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 36, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00638', 'disabled-57f41407', 'disabled-57f41407-moex-110-01c5eaab', 'sub-disabled-57f41407-04', NULL, 'single_choice', '「人生終需一死，絕症病人的死亡，並非醫療的失敗；未能協助病人安詳 往生，才是醫療的失敗。活著，是最好的禮物；善終，是最美的祝福！」 根據上文，下列選項最符合本文旨意的是：', '["減輕死亡的痛苦也屬於醫療的成功", "醫生治療病患皆以善終為最好祝福", "醫療的失敗是沒辦法挽救病患生命", "最好的禮物是讓每個人都能活下來"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:38+00:00", "source_pdf_sha1": "9e93f40d41a4", "answer_pdf_sha1": "6bfdd34d238a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "505", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 37, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00639', 'disabled-57f41407', 'disabled-57f41407-moex-110-01c5eaab', 'sub-disabled-57f41407-04', NULL, 'single_choice', '「在人生奔馳多變的旅程中，心中的那座山將沉甸甸地給你依靠著，在困 頓消沉的逆境時，心中的那座山將高聳地屹立著給你鼓舞的指標。整個世 界都在匆忙地趕路，惟有大屯山毅然挺身而出，不隨波逐流，不輕易更改 容顏。」下列何者最接近本文對山的描述？', '["堅毅不拔", "堅苦卓絕", "無堅不摧", "鑽堅仰高"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:38+00:00", "source_pdf_sha1": "9e93f40d41a4", "answer_pdf_sha1": "6bfdd34d238a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "505", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 38, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00640', 'disabled-57f41407', 'disabled-57f41407-moex-110-01c5eaab', 'sub-disabled-57f41407-04', NULL, 'single_choice', '「教育是一種雙向的互動過程，施教者和受教者都必須盡到自己份內該盡 的責任與義務，懂得知不足而後自反，體悟知困而能自強。」下列何者是 作者所要表達的意思？', '["化民成俗", "因材施教", "百年樹人", "教學相長"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:38+00:00", "source_pdf_sha1": "9e93f40d41a4", "answer_pdf_sha1": "6bfdd34d238a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "505", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 39, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00641', 'disabled-57f41407', 'disabled-57f41407-moex-110-01c5eaab', 'sub-disabled-57f41407-04', NULL, 'single_choice', '「當愛落到行為層面，就要求『愛到』的效果，這叫做『義』。義很難一 發就正中紅心，總須在行為模式的兩極端間揣摩斟酌權衡，這叫做『辨義』 或『擇義』。」根據上文，下列何者符合作者的看法？', '["心中有愛就能充分地體現「義」", "是非分明就是「辨義」的具體表現", "對人表達一己的善意，就叫做「義」", "「擇義」是為了達到「愛到」的效果"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:38+00:00", "source_pdf_sha1": "9e93f40d41a4", "answer_pdf_sha1": "6bfdd34d238a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "505", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 40, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00642', 'disabled-57f41407', 'disabled-57f41407-moex-110-01c5eaab', 'sub-disabled-57f41407-04', NULL, 'single_choice', '「毒品上癮者的家屬，如果花了大半的精力滿足上癮者的需要或處理他留 下的爛攤子，以至於好像掉進永無休止的陷阱裡，和上癮者的關係似乎達 到『失控的狀態』，那麼就可能是『上癮加工者』或者和上癮者產生『相 互依賴』的關係。他的狀況嚴重影響到你，這樣的關係不但無法讓你所愛 的人戒癮，反而會讓你憂鬱、躁鬱、失眠，甚至精神分裂。」根據上文， 下列敘述正確的是：', '["上癮者需在家屬的掌控之下才是安全的", "家屬必須改變態度，讓上癮者自己承擔責任", "家屬即使受到嚴重不良影響，也應該多關愛上癮者", "為了上癮者的名聲，家屬宜為他隱瞞毒品上癮一事"]'::jsonb, 1, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:38+00:00", "source_pdf_sha1": "9e93f40d41a4", "answer_pdf_sha1": "6bfdd34d238a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "505", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 41, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00643', 'disabled-57f41407', 'disabled-57f41407-moex-110-01c5eaab', 'sub-disabled-57f41407-04', NULL, 'single_choice', '「回顧人類文明發展，新科學、新技術總會在不破不立的因果關係鏈中， 引發社會陣痛。……先進科技的出現，或許是『造物主』的善意，或是人 類集體意識的英明決策，一面把人類從舊的產業格局和繁重勞作中解放出 來，一面如鞭策或督促一般，迫使人類做出種種變革。比如AI，它一面釋 放出巨大的生產力，免除人類繼續從事繁冗工作之苦，一面又在用可能出 現的失業問題提醒人類：你應該往前走了！」根據上文，下列選項何者正確？', '["人類文明總是依循著優勝劣汰的法則進化", "科技發展的方向取決於決策者的意識形態", "新技術帶來失業率攀升，是科技發展的危機", "人類須運用智慧創新變革，避免被機器取代"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:38+00:00", "source_pdf_sha1": "9e93f40d41a4", "answer_pdf_sha1": "6bfdd34d238a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "505", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 42, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00644', 'disabled-57f41407', 'disabled-57f41407-moex-110-01c5eaab', 'sub-disabled-57f41407-04', NULL, 'single_choice', '「她於是有了更多正當性可以待在菜園。其實，阿草從來不愛農作，在鄉 下種菜，主要是逃離愛發脾氣的阿嬤，讓阿草尋得一個喘息的空間，不必 受到阿嬤無時無刻的監看。阿嬤雖能生活自理，但見不得下人閒著沒事， 如今阿草種了菜，不但生活花費少了，子女還在收成時期更頻繁返家，明 顯是雇主獲利得多。種植最終成為勞雇關係間的平衡點，阿草從中獲得實 質的成就感，及部分脫逃的自在空間。『那個土真好，那個陽光和雨水， 真是好好種。』阿草說，相較於北寧農地的乾瘠、雨量不可掌握，高雄的 沃土簡直有不勞而獲的錯覺。」下列選項，何者不是「阿草」當時的人生 經驗？', '["人不親土親", "天助自助者", "無心插柳柳成蔭", "虎落平陽被犬欺"]'::jsonb, 3, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:38+00:00", "source_pdf_sha1": "9e93f40d41a4", "answer_pdf_sha1": "6bfdd34d238a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "505", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 43, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL),
  ('disabled-57f41407-moex-00645', 'disabled-57f41407', 'disabled-57f41407-moex-110-01c5eaab', 'sub-disabled-57f41407-04', NULL, 'single_choice', '「在這清淨的水中，臺灣特有種的蓋斑鬥魚時時從水草間浮起，吐著小泡 沫來營造牠的愛巢。牠那斑斕的體色以及飄逸多姿的長鰭，能使最沒有美 感的人也著迷。幾隻黃黑相間的蝶蜓，在青蔥的池岸禾草間追逐嬉戲、飛 飛停停，纖細的豆娘在臺灣萍蓬草的黃花間悠閒地緩緩飛行，偶爾一隻鮮 豔的孔雀蛺蝶，低低掠過水面，飛投對岸。這些小小的生物，使這一方小 池子變得生動活潑起來。」根據上文，下列何者最切近文中描述的狀態？', '["生意盎然", "大音希聲", "沉魚落雁", "兔走烏飛"]'::jsonb, 0, NULL, TRUE, 'official', TRUE, 1, '{"parser_version": "moex_license_v1.0", "parsed_at": "2026-04-25T12:38:38+00:00", "source_pdf_sha1": "9e93f40d41a4", "answer_pdf_sha1": "6bfdd34d238a", "source_family": "moex-gov-tw", "moex": {"exam_code": "110050", "c": "505", "s": "0105", "q": "1"}, "raw_section_label": "本試題為單一選擇題", "subject": "國文(包括公文格式用語)", "year": "110", "exam_name": "110年公務人員特種考試關務人員考試、身心障礙人員考試、國軍上校以上軍官轉任公務人員考試", "original_question_number": 44, "answer_corrected": false, "flags": [], "civil_slug": "disabled", "civil_category": "錄事"}'::jsonb, NULL)
